	('6aad78e3-7f6c-4592-855b-8e23d3c25134', '2f310cc9-454d-4032-8e01-25a493a0a203', '🔔募集原稿アーカイブ', NULL, '【Proプラン限定】AI求人原稿のアーカイブ管理', 'AI求人メーカーで作成したすべての履歴を自動で保存します。
