	('340b1610-665c-48c9-8e64-37755da227c3', '194390c5-dafd-482b-b979-60f165b7ae28', '💡SaaSサービス管理', NULL, 'SaaSサービス機能の管理', '「SaaSサービス機能の登録」、各条件で有効・無効を設定する。', 200, '/system-master', '74f8e05b-c99d-45ee-b368-fdbe35ee0e52', NULL, 'saas_adm', '公開'),
	('8a3342da-47a1-4596-a2bb-4a5d264a3166', '5b1dd5b0-e263-4538-984e-b4f01b729717', '① 納入登録（QRスキャン）', NULL, '納入登録（QRスキャン）', '１．（株）ミューの担当者が納入時にスマートデバイスでラベルのQRコードをスキャンします 。
